### release-please YAML extra-files

release-please natively supports bumping versions in YAML files via `extra-files` with `type: yaml`. The `jsonpath` field uses JSONPath syntax to target the specific key:

```json
{
  "release-type": "simple",
  "packages": {
    ".": {
      "extra-files": [
        {
          "type": "yaml",
          "path": "addon/config.yaml",
          "jsonpath": "$.version"
        }
      ]
    }
  }
}
```

Source: [release-please docs](https://github.com/googleapis/release-please/blob/main/docs/customizing.md)

## Example: Minimal Custom Component with Service

```python
# custom_components/pi_agent/__init__.py
"""Pi Agent integration — registers pi_agent.ask service."""
import asyncio
import logging
from typing import Any

import aiohttp
import voluptuous as vol

from homeassistant.core import HomeAssistant, ServiceCall, ServiceResponse, SupportsResponse
from homeassistant.helpers import config_validation as cv
from homeassistant.helpers.typing import ConfigType

_LOGGER = logging.getLogger(__name__)

DOMAIN = "pi_agent"
ADDON_URL = "http://local-pi-agent:9199"  # Internal Docker network
SERVICE_ASK = "ask"
DEFAULT_TIMEOUT = 120

SERVICE_SCHEMA = vol.Schema({
    vol.Required("question"): cv.string,
    vol.Optional("timeout", default=DEFAULT_TIMEOUT): cv.positive_int,
})

async def async_setup(hass: HomeAssistant, config: ConfigType) -> bool:
    """Set up Pi Agent integration."""

    async def handle_ask(call: ServiceCall) -> ServiceResponse:
        """Handle pi_agent.ask service call."""
        question = call.data["question"]
        timeout = call.data.get("timeout", DEFAULT_TIMEOUT)

        try:
            async with aiohttp.ClientSession() as session:
                async with session.post(
                    f"{ADDON_URL}/ask",
                    json={"question": question},
                    timeout=aiohttp.ClientTimeout(total=timeout),
                ) as resp:
                    if resp.status == 200:
                        result = await resp.json()
                        return {"response": result.get("response", "")}
                    else:
                        error = await resp.text()
                        _LOGGER.error("Pi Agent error: %s", error)
                        return {"error": error}
        except asyncio.TimeoutError:
            _LOGGER.error("Pi Agent request timed out after %ds", timeout)
            return {"error": f"Timeout after {timeout}s"}
        except aiohttp.ClientError as err:
            _LOGGER.error("Pi Agent connection error: %s", err)
            return {"error": str(err)}

    hass.services.async_register(
        DOMAIN,
        SERVICE_ASK,
        handle_ask,
        schema=SERVICE_SCHEMA,
        supports_response=SupportsResponse.OPTIONAL,
    )

    return True
```

## Example: services.yaml
```yaml
ask:
  name: Ask Pi Agent
  description: Send a question to the Pi Agent for processing.
  fields:
    question:
      name: Question
      description: The question or instruction for the Pi Agent.
      required: true
      example: "Turn off all lights in the living room"
      selector:
        text:
          multiline: true
    timeout:
      name: Timeout
      description: Maximum seconds to wait for a response.
      default: 120
      selector:
        number:
          min: 10
          max: 600
          unit_of_measurement: seconds
```

## Example: HTTP Server in Add-on (Node.js)
```javascript
// Simple HTTP server for receiving service calls
const http = require('http');
const { spawn } = require('child_process');

const PORT = 9199;

const server = http.createServer(async (req, res) => {
  if (req.method === 'POST' && req.url === '/ask') {
    let body = '';
    req.on('data', chunk => body += chunk);
    req.on('end', () => {
      const { question } = JSON.parse(body);
      // Spawn pi process with question
      const pi = spawn('pi', ['--non-interactive', '-m', question]);
      let output = '';
      pi.stdout.on('data', data => output += data);
      pi.stderr.on('data', data => output += data);
      pi.on('close', code => {
        res.writeHead(200, {'Content-Type': 'application/json'});
        res.end(JSON.stringify({ response: output, exit_code: code }));
      });
    });
  } else {
    res.writeHead(404);
    res.end();
  }
});

server.listen(PORT, '0.0.0.0');
```

## Implementation Research

### Current State
- **32 tool files** in `.pi/extensions/home-assistant/tools/ha-*.ts`
- Each registers via `pi.registerTool()` with a `description` field containing full docs
- All registered in `index.ts` via individual `register*Tool(pi)` calls
- **2 tools have dynamic descriptions** using template literals:
  - `ha_helpers`: `${allDomains.join(", ")}` — list of supported helper domains from `supportedDomains()`
  - `ha_restart`: `${RELOADABLE_DOMAINS.join(", ")}` — list of reloadable domains

### Implementation Plan

#### 1. Create `tools/ha-tool-docs.ts`

Structure:
```typescript
import type { ExtensionAPI } from "@mariozechner/pi-coding-agent";
import { Type } from "@sinclair/typebox";
import { supportedDomains } from "../lib/helpers/registry.js";

// Static docs for 30 tools + 2 dynamic ones built at registration time
const TOOL_DOCS: Record<string, string> = { ... };

export function registerToolDocsTool(pi: ExtensionAPI) {
  // Add dynamic docs at registration time
  TOOL_DOCS.ha_helpers = `...${supportedDomains().join(", ")}...`;
  TOOL_DOCS.ha_restart = `...${RELOADABLE_DOMAINS}...`;

  pi.registerTool({ name: "ha_tool_docs", ... });
}
```

#### 2. Short descriptions pattern

Each tool keeps ~1 line: `<purpose>. Actions: <list>. Use ha_tool_docs('<name>') for full usage.`

#### 3. Dynamic descriptions issue

For `ha_helpers` and `ha_restart`, the short description can just list actions without the domain list. The full domain list goes into `TOOL_DOCS` and is also available in the parameter `description` field (which stays unchanged).

#### 4. No changes needed to:
- Tool parameters (keep as-is)
- Tool execute functions (keep as-is)
- `index.ts` registration order (just add `registerToolDocsTool`)

### Files to modify
- **Create**: `tools/ha-tool-docs.ts` (new)
- **Edit**: all 32 `tools/ha-*.ts` files (shorten `description` field only)
- **Edit**: `index.ts` (add import + registration call)

## Incremental Update & Queue Strategy

### Granular updates (no full rebuild)
When a single entity/device/area changes, only update that node and its edges — don't rebuild the whole graph:
- **Entity registry change** → replace that entity's node, re-scan its edges (area, device, labels)
- **Device registry change** → replace device node + update entity→device edges
- **Automation YAML change** → re-parse that one file, replace its edges (entity references, triggers, conditions, actions)
- **State change** → update the node's state attribute only (no edge changes)

### Coalescing / queue strategy
Multiple rapid updates (e.g. bulk entity rename) need smart handling:
- **Debounce window** (e.g. 500ms) — collect all changes, then apply as one batch
- **If a rebuild IS running and new changes arrive** — cancel/abort current rebuild, restart with the latest state (last-write-wins)
- **File watcher debounce** — HA often writes `.storage` files in bursts (multiple registries updated together). Collect all changed files in the debounce window, then process together.

### Implementation sketch:
```
let pendingChanges: Set<string> = new Set();
let rebuildTimer: NodeJS.Timeout | null = null;

function onChangeDetected(targetId: string) {
  pendingChanges.add(targetId);
  if (rebuildTimer) clearTimeout(rebuildTimer);
  rebuildTimer = setTimeout(() => {
    const batch = [...pendingChanges];
    pendingChanges.clear();
    applyIncrementalUpdates(batch);
  }, 500);
}
```

